// ============================================================
// DISPATCHER CODE NODE v3.0
// Cross-JOIN + Filtro Día + Detección Automática de Semana
// ============================================================
// CAMBIO CLAVE: Ya no busca Estado='Activo'.
// Ahora CALCULA el lunes de la semana actual y lo compara
// contra la columna Fecha_Lunes_Referencia de Temas_Semanales.
// Esto elimina la necesidad de cambiar manualmente el estado.
// ============================================================

const temasItems  = $('GSheets - Temas').all();
const sitiosItems = $('GSheets - Sitios').all();
const perfilesItems = $('GSheets - Perfiles').all();

// ---- 1. Calcular el LUNES de la semana actual ----
const now = new Date();
const dayOfWeek = now.getDay(); // 0=Dom, 1=Lun, 2=Mar, ... 6=Sáb
// Fórmula: retroceder al lunes más cercano
// Si es domingo (0), retroceder 6 días; si no, retroceder (dayOfWeek - 1)
const diffToMonday = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
const monday = new Date(now);
monday.setDate(now.getDate() + diffToMonday);

// Formato YYYY-MM-DD para comparación
const mondayISO = monday.toISOString().split('T')[0]; // "2026-03-16"

// ---- 2. Encontrar el tema de ESTA semana ----
// Google Sheets puede devolver la fecha en varios formatos:
// "2026-03-16", "03/16/2026", "16/03/2026", "March 16, 2026", 
// o incluso un serial de Sheets. Normalizamos todo a YYYY-MM-DD.
function normalizeDateToISO(raw) {
  if (!raw) return '';
  const str = String(raw).trim();

  // Ya es ISO: "2026-03-16" o "2026-03-16T00:00:00..."
  if (/^\d{4}-\d{2}-\d{2}/.test(str)) {
    return str.substring(0, 10);
  }

  // Formato MM/DD/YYYY (US)
  if (/^\d{1,2}\/\d{1,2}\/\d{4}$/.test(str)) {
    const [m, d, y] = str.split('/');
    return `${y}-${m.padStart(2, '0')}-${d.padStart(2, '0')}`;
  }

  // Formato DD/MM/YYYY (EU/MX)
  if (/^\d{1,2}-\d{1,2}-\d{4}$/.test(str)) {
    const [d, m, y] = str.split('-');
    return `${y}-${m.padStart(2, '0')}-${d.padStart(2, '0')}`;
  }

  // Google Sheets serial number (días desde 1899-12-30)
  if (/^\d{5}$/.test(str)) {
    const epoch = new Date(1899, 11, 30);
    epoch.setDate(epoch.getDate() + parseInt(str));
    return epoch.toISOString().split('T')[0];
  }

  // Fallback: intentar parsear con Date()
  try {
    const parsed = new Date(str);
    if (!isNaN(parsed.getTime())) {
      return parsed.toISOString().split('T')[0];
    }
  } catch (e) { /* ignore */ }

  return str; // Devolver tal cual si no se puede parsear
}

const tema = temasItems.find(i => {
  const fechaRef = normalizeDateToISO(i.json.Fecha_Lunes_Referencia);
  return fechaRef === mondayISO;
})?.json;

if (!tema) {
  // No hay tema programado para esta semana
  // Esto puede pasar si no se llenó la fila en Google Sheets
  console.log(`⚠️ No se encontró tema para la semana del ${mondayISO}`);
  console.log(`   Fechas disponibles: ${temasItems.map(i => i.json.Fecha_Lunes_Referencia).join(', ')}`);
  return [];
}

// ---- 3. Detectar el día de HOY (español, sin acentos, lowercase) ----
const hoy = new Date()
  .toLocaleDateString('es-MX', { weekday: 'long' })
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '');

const fechaHoy = new Date().toISOString().split('T')[0];

// ---- 4. Filtrar sitios activos que publican HOY ----
const sitiosHoy = sitiosItems.filter(s => {
  const diaSitio = (s.json.Dia_Publicacion || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');
  return diaSitio === hoy && String(s.json.activo).toUpperCase() === 'TRUE';
});

if (sitiosHoy.length === 0) {
  // Ningún sitio publica hoy (ej. sábado/domingo)
  return [];
}

// ---- 5. Cross-JOIN: sitio × perfil × tema → payload Worker ----
return sitiosHoy.map(s => {
  const site = s.json;
  const perfil = perfilesItems.find(
    p => p.json.perfil_id === site.perfil_id
  )?.json || {};

  // Determinar idioma de instrucción para el system prompt
  const idiomaInstruccion = site.idioma === 'es'
    ? 'español neutro'
    : 'English';

  // Sustituir {{PLACEHOLDERS}} en el system_prompt_template
  let systemPromptFinal = perfil.system_prompt_template || '';
  const replacements = {
    '{{AUTHOR_NAME}}':        perfil.author_name || '',
    '{{AUTHOR_TITLE}}':       perfil.author_title || '',
    '{{AUTHOR_BIO}}':         perfil.author_bio || '',
    '{{IDIOMA_INSTRUCCION}}': idiomaInstruccion,
    '{{PUBLISHER_NAME}}':     site.publisher_name || '',
    '{{PUBLISHER_URL}}':      site.wp_url || '',
    '{{CATEGORY_URL}}':       site.category_url || '',
    '{{CTA_COPY}}':           site.cta_copy || '',
  };

  for (const [token, value] of Object.entries(replacements)) {
    systemPromptFinal = systemPromptFinal.split(token).join(value);
  }

  // ---- 6. Construir el payload estandarizado para el Worker ----
  return { json: {
    // --- Identificación ---
    site_id:              site.site_id,

    // --- Credenciales WP (viajan en payload, NUNCA hardcodeadas) ---
    wp_url:               site.wp_url,
    wp_user:              site.wp_user,
    wp_app_password:      site.wp_app_password,

    // --- Tema de la semana (automático por fecha) ---
    tema_semanal:         tema.Tema_Principal || '',
    angulo_enfoque:       tema.Angulo_Enfoque || '',

    // --- Config del sitio ---
    idioma:               site.idioma,

    // --- System Prompts ya procesados ---
    system_prompt_final:           systemPromptFinal,
    art_director_system_prompt:    perfil.art_director_system_prompt || '',

    // --- Metadata del perfil de escritor ---
    author_name:          perfil.author_name || '',
    author_title:         perfil.author_title || '',
    author_bio:           perfil.author_bio || '',

    // --- Publisher info ---
    publisher_name:       site.publisher_name || '',
    publisher_url:        site.wp_url || '',
    category_url:         site.category_url || '',
    cta_copy:             site.cta_copy || '',

    // --- Fecha/hora de publicación programada ---
    wp_scheduled_date:    `${fechaHoy}T${site.Hora_Publicacion || '07:00'}:00`,

    // --- Debug info (útil para troubleshooting) ---
    _debug_semana_detectada: mondayISO,
    _debug_dia_detectado:    hoy,
  }};
});
